4	const FIRST_INSURANCE_RATE = 0.1;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	
8	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
9	type Step = { op: string; items: QuoteItem[] };
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  amulet: 60,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_OF_THREE_BASE = 60;
19	const BLOCK_SIZE = 3;
20	
21	const basePremiumForItem = (item: QuoteItem): number =>
22	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
23	
24	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
25	  items.reduce((groups, item) => {
26	    const group = groups.get(item.type) ?? [];
27	    return groups.set(item.type, [...group, item]);
28	  }, new Map<string, QuoteItem[]>());
29	
30	const itemSurcharges = (item: QuoteItem, base: number): number => {
31	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
32	  const highEnch =
33	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
34	  const firstInsurance = base * FIRST_INSURANCE_RATE;
35	  return curse + highEnch + firstInsurance;
36	};
37	
38	const itemPremium = (item: QuoteItem): number => {
39	  const base = basePremiumForItem(item);
40	  return base + itemSurcharges(item, base);
41	};
42	
43	const groupPremium = (type: string, group: QuoteItem[]): number =>
44	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE
45	    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
46	    : group.reduce((sum, item) => sum + itemPremium(item), 0);
47	
48	const sumItemPremiums = (items: QuoteItem[]): number =>
49	  [...groupByType(items)].reduce(
50	    (total, [type, group]) => total + groupPremium(type, group),
51	    0,
52	  );
53	
54	const quoteStep = (step: Step) => ({
55	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
56	});
57	
58	export const runScenario = (scenario: unknown): unknown => {
59	  const { steps } = scenario as Scenario;
60	  return { results: steps.map(quoteStep) };
61	};
